//ChatGPT
function removeElement(arr, value) {
  return arr.filter(item => item !== value);
}

function sortWithPair(A, B) {
  const indices = A.map((_, i) => i)
                   .sort((i, j) => A[i] - A[j]);

  return {
    A: indices.map(i => A[i]),
    B: indices.map(i => B[i])
  };
}


              //A現在時刻　B発車時刻
function diffTime(a, b) {
  const ah = Number(a.slice(0, 2));
  const am = Number(a.slice(2, 4));

  const bh = Number(b.slice(0, 2));
  const bm = Number(b.slice(2, 4));

  const totalA = ah * 60 + am;
  const totalB = bh * 60 + bm;

  return totalB - totalA;
}

console.log(diffTime("1313", "1318")); // 5
console.log(diffTime("2103", "2059")); // -4

function formatTime(num) {
  // 小数点以下を切り捨て
  let intPart = Math.floor(Number(num));

  // 6桁になるように先頭を0埋め
  return String(intPart).padStart(6, '0');
}

// 使用例
console.log(formatTime("073000.56")); // 073000
console.log(formatTime("73000.56"));  // 073000
console.log(formatTime("123456.78")); // 123456
























