ws.onmessage = (event) => {
  console.log("Received:", event.data);
  if(event.data.split('@')[0] === 'qia' && mode === 3)  {
    if(ws.readyState === WebSocket.OPEN) {
      ws.send('train@' + infolist.join(','));
    } else {
      alert('接続切断');
    }
  } else {
    info = event.data
  let headerinvestigater = info.split('@');
  if(headerinvestigater[0] === 'train' && info !== '') {
    output.textContent = info;
  }
  console.log(headerinvestigater, headerinvestigater[0]);
  if(headerinvestigater[0] === 'train') {
    infolist = headerinvestigater[1].split(','); //列車ごとにわけて
  } else if(headerinvestigater[0] === 'now') {
    currenttime = headerinvestigater[1];
    if(Number(currenttime) % 1 === 0) {
      shower.nowtime.textContent = '只今の時刻：' + currenttime;
    } else if(Number(currenttime) % 1 === NaN) {
      shower.nowtime.textContent = '只今の時刻　バグ発生中' + currenttime;
    } else {
      shower.nowtime.textContent = '只今の時刻：' + formatTime(currenttime);
    }
    
    document.getElementById('timesetform').value = headerinvestigater[1];
  }
  
  
  if(mode !== 3) {
    console.log(mode !== 3);
    investigatesituation();
  } else {

    drawinmap();
    if(headerinvestigater[0] === 'train') {
      saveddata.push(currenttime + '###' + info);
    }
  }
  }
  
  
};






